import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { AgedStockRow } from '../../../services/analytics/models';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
const AGE_OPTIONS = [{ value: '30', label: '30+ ngày' }, { value: '60', label: '60+ ngày' }, { value: '90', label: '90+ ngày' }, { value: '180', label: '180+ ngày' }, { value: '365', label: '1 năm+' }];
const BaoCaoTonKhoCuPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const [minDays, setMinDays] = useState('90');
  const [rows, setRows] = useState<AgedStockRow[]>([]);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ analyticsService.getAgedStock({ minDays: Number(minDays) }).then(d=>{if(!c)setRows(d);}).catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));}).finally(()=>{if(!c)setLoading(false);}); },0); return ()=>{c=true;clearTimeout(t);}; }, [minDays,dispatch, reloadKey]);
  const refresh = () => setReloadKey(k => k + 1);
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-hourglass-half" /> Tồn kho lâu ngày</h1><p className={styles.subtitle}>{rows.length} dòng</p></div>
        <div className={styles.headerActions}><Button variant="secondary" onClick={()=>exportExcel('/wms/reports/aged-stock/export-excel',{minDays},`TonKhoCu-${minDays}ngay.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.filtersBar} data-testid={`erp-bao-cao-ton-kho-cu-filters`}><Select value={minDays} onChange={e=>setMinDays(e.target.value)} options={AGE_OPTIONS} size="small" /><ListSearchRefreshButtons testIdPrefix="erp-bao-cao-ton-kho-cu" onSearch={handleSearch} onRefresh={refresh} showSearch={false} /></div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:rows.length===0?<div className={styles.empty}><p>Không có dữ liệu</p></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr><th>Mã</th><th>Tên</th><th>Kho</th><th className={styles.colRight}>SL</th><th className={styles.colRight}>GT</th><th>Ngày ĐC</th><th className={styles.colRight}>Tuổi (ngày)</th></tr></thead><tbody>{rows.map((r,i)=>(<tr key={i} className={r.ageDays>=180?styles.rowDanger:undefined}><td>{r.productCode}</td><td>{r.productName}</td><td>{r.warehouseName}</td><td className={styles.colRight}>{formatNumber(r.qty)}</td><td className={styles.colRight}>{formatVnd(r.totalValue)}</td><td>{formatDate(r.lastMovementDate)}</td><td className={styles.colRight}>{r.ageDays}</td></tr>))}</tbody></table></div>}</div>
    </div>
  );
};
export default BaoCaoTonKhoCuPage;
